const salida = [];

for (const item of items) {
  // TOMAMOS LOS CAMPOS SEGÚN TU ESTRUCTURA REAL
  const mensaje   = item.json.conversation || "";  // <- AQUÍ ESTÁ EL TEXTO
  const id        = item.json.id || null;
  const nombre    = item.json.name || null;
  const contacto  = item.json.contact || null;
  const fecha     = item.json.fecha || null;

  // --- INTENCIÓN ---
  const esReserva = /cita|reservar|reserva/i.test(mensaje);

  // --- EXTRACCIÓN DE HORA ---
  let horaTexto = null;
  let hora24 = null;

  if (mensaje) {
    const texto = mensaje;

    // 1) Primero: horas con AM/PM, ej: "10:00 a.m", "7 pm"
    const regexAmPm = /(\d{1,2})\s*(?::(\d{2}))?\s*(a\.?m\.?|p\.?m\.?)/gi;
    let matchAmPm;
    let ultimaAmPm = null;

    while ((matchAmPm = regexAmPm.exec(texto)) !== null) {
      ultimaAmPm = matchAmPm; // nos quedamos con la última
    }

    if (ultimaAmPm) {
      let hora = parseInt(ultimaAmPm[1], 10);
      const minutos = ultimaAmPm[2] ? parseInt(ultimaAmPm[2], 10) : 0;
      const ampm = ultimaAmPm[3] ? ultimaAmPm[3].toLowerCase() : null;

      if (ampm) {
        if (ampm.includes('p') && hora !== 12) hora += 12;
        if (ampm.includes('a') && hora === 12) hora = 0;
      }

      const mm = minutos.toString().padStart(2, '0');
      const hh = hora.toString().padStart(2, '0');

      horaTexto = ultimaAmPm[0];      // texto original, ej: "10:00 a.m"
      hora24 = `${hh}:${mm}`;         // ej: "10:00"
    } else {
      // 2) Si no hay AM/PM, buscamos formato 24h: "19:00", "09:30"
      const regex24 = /\b([01]?\d|2[0-3]):([0-5]\d)\b/g;
      let match24;
      let ultima24 = null;

      while ((match24 = regex24.exec(texto)) !== null) {
        ultima24 = match24;
      }

      if (ultima24) {
        const hora = parseInt(ultima24[1], 10);
        const minutos = parseInt(ultima24[2], 10);

        const mm = minutos.toString().padStart(2, '0');
        const hh = hora.toString().padStart(2, '0');

        horaTexto = ultima24[0];
        hora24 = `${hh}:${mm}`;
      }
    }
  }

  // --- REFERENCIA DE FECHA EN EL TEXTO ---
  let fechaReferencia = null;
  if (/hoy/i.test(mensaje)) fechaReferencia = 'hoy';
  else if (/mañana/i.test(mensaje)) fechaReferencia = 'mañana';

  // --- SALIDA LISTA PARA ANÁLISIS (sin campos null) ---
  const obj = {
    id,
    nombre,
    contacto,
    texto_original: mensaje,
    fecha_hora_recibido: fecha,
    intencion: esReserva ? 'solicitud_cita' : 'desconocida',
  };

  if (horaTexto) obj.hora_detectada_texto = horaTexto;
  if (hora24) obj.hora_detectada_24h = hora24;
  if (fechaReferencia) obj.fecha_referencia_texto = fechaReferencia;

  salida.push({ json: obj });
}

return salida;

const resultados = [];

for (const item of items) {
  const data = item.json;

  // ==============================
  // 1) NOMBRE
  // ==============================
  const nombre = data.nombre || data.nombre_cliente || "cliente";

  // ==============================
  // 4) DISPONIBILIDAD ESTÁTICA (la movemos arriba)
  // ==============================
  const disponibilidad = [
    { date: "2025-12-06", time: "19:00", available: false },
    { date: "2025-12-06", time: "20:00", available: true },

    { date: "2025-12-07", time: "10:00", available: true },
    { date: "2025-12-07", time: "13:00", available: true },
    { date: "2025-12-07", time: "19:00", available: false }
  ];

  // Lista de horarios disponibles (true)
  const listaDisponibles = disponibilidad
    .filter(s => s.available)
    .map(s => `${s.date} ${s.time}`)
    .join(", ");

  // ==============================
  // 2) FECHA EXTRAÍDA DEL MENSAJE
  // ==============================
  let fecha = data.fecha_reserva || null;

  if (!fecha && data.texto_original) {
    const texto = data.texto_original;
    const regexFecha = /(\d{4})[-\/\.](\d{2})[-\/\.](\d{2})/;
    const coinc = texto.match(regexFecha);
    if (coinc) fecha = `${coinc[1]}-${coinc[2]}-${coinc[3]}`;
  }

  if (!fecha && data.fecha_hora_recibido) {
    const d = new Date(data.fecha_hora_recibido);
    const ref = (data.fecha_referencia_texto || "").toLowerCase().trim();
    if (ref === "mañana") d.setDate(d.getDate() + 1);
    fecha = d.toISOString().split("T")[0];
  }

  // ==============================
  // 3) HORA desde entrada
  // ==============================
  let hora = data.hora_reserva || data.hora_detectada_24h || null;

  // Si falta fecha u hora, mostramos horarios disponibles pero SIN imprimir null
  if (!fecha || !hora) {
    resultados.push({
      json: {
        disponible: false,
        respuesta_cliente:
          "Hola " + $('Datos').first().json.name +
          ", no tenemos disponibilidad en la hora indicada. ¿Podrías indicarme la fecha (YYYY-MM-DD) y otra hora?" +
          (listaDisponibles ? " Horarios disponibles: " + listaDisponibles : "")
      }
    });
    continue;
  }

  // ==============================
  // ORDENAR PARA SUGERENCIAS
  // ==============================
  const disponibilidadOrdenada = [...disponibilidad].sort((a, b) => {
    if (a.date === b.date) return a.time.localeCompare(b.time);
    return a.date.localeCompare(b.date);
  });

  // ==============================
  // 5) CHEQUEO EXACTO
  // ==============================
  const match = disponibilidad.find(slot => slot.date === fecha && slot.time === hora);
  let disponible = match ? !!match.available : false;

  // ==============================
  // 6) CONSTRUIR RESPUESTA
  // ==============================
  let respuesta;

  if (disponible) {
    respuesta =
      "Hola " + nombre +
      ", tenemos disponibilidad el " + fecha +
      " a las " + hora +
      ". ¿Deseas que confirme tu cita?" +
      (listaDisponibles ? "\n\nHorarios disponibles: " + listaDisponibles : "");
  } else {
    let siguienteSlot = null;

    for (const slot of disponibilidadOrdenada) {
      if (!slot.available) continue;
      if (slot.date < fecha) continue;
      if (slot.date === fecha && slot.time <= hora) continue;
      siguienteSlot = slot;
      break;
    }

    if (siguienteSlot) {
      if (siguienteSlot.date === fecha) {
        respuesta =
          "Hola " + nombre +
          ", no tenemos disponibilidad el " + fecha +
          " a las " + hora +
          ". El siguiente horario disponible ese día es a las " +
          siguienteSlot.time + ". ¿Te gustaría reservarlo?";
      } else {
        respuesta =
          "Hola " + nombre +
          ", no tenemos disponibilidad el " + fecha +
          " a las " + hora +
          ". El siguiente horario disponible es el " +
          siguienteSlot.date + " a las " + siguienteSlot.time +
          ". ¿Te gustaría reservarlo?";
      }
    } else {
      respuesta =
        "Hola " + nombre +
        ", no tenemos disponibilidad el " + fecha +
        " a las " + hora +
        " ni contamos con otros horarios disponibles en las fechas configuradas. ¿Te gustaría intentar con otra fecha?";
    }

    if (listaDisponibles) {
      respuesta += "\n\nHorarios disponibles: " + listaDisponibles;
    }
  }

  //  Construimos el output SIN imprimir null
  const salida = {
    disponible,
    respuesta_cliente: respuesta
  };
  if (fecha) salida.fecha_reserva = fecha;
  if (hora) salida.hora_reserva = hora;

  resultados.push({ json: salida });
}

return resultados;
